INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (1, '旧鱼线轮', '二手货，明显是从废品收购站淘出来的，能用就行。', 1, 'general', 1, 1.02, 0, 1.02, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (2, '帆布鱼篓', '普通工艺品，便利店的折扣货架上常年堆着。不漏水、不漏鱼，朴素但合格，钓友的入门标配。', 2, 'general', 1.01, 1.03, 0, 1.04, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (3, '防滑钓鱼手套', '防滑防割的钓鱼专用手套，提竿不易脱手。简单又实用，戴着它你才有钓鱼佬的样子——尽管隔壁那位赤手空拳的大爷比你钓得多。', 3, 'general', 1.02, 1.03, 0, 1.06, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (4, '偏光太阳镜', '滤掉水面反光，资深钓友升级款，戴上后你会发现"诶？这水下原来这么有戏"，也会开始觉得"欸，怎么要买的东西越来越贵"。', 4, 'general', 1.04, 1.04, 0.01, 1.08, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (5, '多功能渔具背心', '多口袋、多挂钩、多腰带的"钓友战术背心"，看起来像要去打仗。但仔细想想，跟鱼这种东西斗智斗勇也确实跟打仗差不多，尤其是当你忘了把面包屑放进哪个口袋的时候。', 5, 'general', 1.06, 1.04, 0.02, 1.13, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (6, '便携式电子鱼探仪', '手持声呐，屏幕上能粗略标记水下深度和鱼群分布。入门级渔获作弊器，但毕竟"知道鱼在哪"和"钓得到鱼"是两回事，它只解决第一个问题。', 6, 'general', 1.08, 1.06, 0.02, 1.18, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (7, '蠕动眼瞳护符', '一颗一直转动注视的眼球，挂在脖子上当护符。你不太确定它是看着鱼还是看着你；但反正没发生别的事，你也没想太多。', 7, 'general', 1.12, 1.08, 0.04, 1.22, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (8, '胎膜手套', '像第二层皮一样贴合手掌的薄膜手套，会渗血。戴着它的手钓鱼有奇效，水里的东西好像把它当成了同类。', 7, 'general', 1.15, 1.12, 0.02, 1.2, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (9, '哀鸣项链', '项链上串着会自己呜咽的小肉块，听起来像是婴儿在哭。鱼听了会受惊，往哪都想躲，然后就躲到了你的鱼钩上。', 7, 'general', 1.1, 1.15, 0.03, 1.21, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (10, '镇魂铃', '挂在腰间的青铜小铃，鱼听见铃声便心境澄明、不再挣扎。也有修士说这铃声其实是镇压死灵的。', 7, 'general', 1.15, 1.08, 0.02, 1.22, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (11, '太极鱼坠', '阴阳调和的玉坠，钓获亦阴阳调和；一半是上品鱼，一半是下品鱼。嗯，总比一半都没有强吧？', 7, 'general', 1.16, 1.13, 0.01, 1.2, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (12, '紫府符纸', '他们都说这是"大能加持过的"，但你怀疑只是普通宣纸盖了个章。当然，加持没加持鱼说了算，鱼似乎挺买账。', 7, 'general', 1.13, 1.1, 0.03, 1.21, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (13, '藤蔓编织鱼篓', '森林德鲁伊培育的活体容器……话是这么说，其实就是用藤蔓编了个鱼篓而已，怎么敢卖十倍价的？！', 7, 'general', 1.1, 1.18, 0.01, 1.2, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (14, '海洋之心', '传说镶嵌于古海王王冠正中的蔚蓝巨钻，承载着他对所有水族子民的最后祝福。王朝覆灭后宝石散落人间，几经辗转才到了你的手上。', 7, 'general', 1.13, 1.09, 0.03, 1.23, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (15, '古龙之息', '采自巨龙巢穴，那里的硫磺晶簇浸透了龙的呼吸。气味浓烈到能让胆小的鱼贩退避三舍，但水里偏有那么些好奇的家伙，会遇到你和你的鱼钩。', 7, 'general', 1.12, 1.1, 0.04, 1.22, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (16, '虚空虹吸戒指', '据说镶砌着微型黑洞碎片，如果是真的的话你大概已经被吸进去了。虽然它好像确实有点像磁铁一样吸鱼，偶尔也会吸到隔壁钓友鱼篓里面的。', 7, 'general', 1.1, 1.16, 0.01, 1.21, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (17, '全息渔获扫描仪', '小型全息投影仪，能实时显示水下分布。几乎能看清每条鱼的眼睛，但其造价仍不足以继承价值判断模组。', 7, 'general', 1.12, 1.09, 0.04, 1.22, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (18, 'AI 鱼饵决策器', '内置小型 AI，会自动调整鱼饵参数让你的钓获最优化。它有时候会发出自言自语般的乱码，也就是所谓的机器学习的"不可解释性"。', 7, 'general', 1.14, 1.09, 0.02, 1.23, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (19, '黄印怀表', '青铜外壳的朴素计时器，它只会擅自进行倒计时，每次倒计时都代表着你有大鱼上钩；但绝对不能亲眼看见倒计时归零的那个瞬间……', 8, 'general', 1.15, 1.12, 0.05, 1.27, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (20, '孕梦珊瑚戒指', '猩红珊瑚枝环成的戒指仍在擅自增殖，持有它的每晚你都在做噩梦，你大汗淋漓地醒来……但不太能记得梦见了什么。', 8, 'general', 1.21, 1.14, 0.02, 1.25, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (21, '同心眼网袋', '装满眨眼的眼球的小布袋，挂在腰间一抖就听见眨眼声"啪啪啪"。鱼很怕被这样注视，所以接近你时会下意识地张大眼睛，然后就惊讶地咬钩。', 8, 'general', 1.16, 1.16, 0.04, 1.26, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (22, '青鸾褪羽', '"清唳惊幽涧，凡鳞拜羽旌"', 8, 'general', 1.21, 1.11, 0.02, 1.26, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (23, '心魔标', '此浮标会在水面扬起你的心魔虚影引诱你提竿，这种压制心魔的修炼颇有益处，但如果提错竿了会发生什么还是别问了。', 8, 'general', 1.17, 1.16, 0.05, 1.24, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (24, '通幽玉佩', '通晓水下灵性的古玉，戴着它你能"感觉"到水底某条特别的鱼正在等你。你说不上来为什么，但它说"是你"。', 8, 'general', 1.18, 1.1, 0.04, 1.27, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (25, '水妖的发丝腕带', '把水妖的头发当腕带，为了保持原味因此无需清洗，发丝间缠绕的不明卵让你感觉恶心，但这个味道似乎还真把鱼给吸引过来了。', 8, 'general', 1.14, 1.22, 0.01, 1.24, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (26, '丰收号角', '传说中的神器，吹响即可吸引鱼群。只有不看使用说明的人会在钓的中途吹，反而把鱼给全部吓跑。', 8, 'general', 1.16, 1.2, 0.02, 1.25, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (27, '圣杯水滴', '装着永流不竭圣水的微缩杯，一滴水能净化一片水域，鱼也开始觉得这片水变好了，纷纷涌来。但你忘了水变好了鱼就更聪明了。', 8, 'general', 1.18, 1.12, 0.02, 1.27, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (28, '时间沙漏钓坠', '有时停效果的神器，能让刚钓上来的鱼就像在水里一样新鲜……嗯？但是直接放鱼篓再放水里不就行了吗？……', 8, 'general', 1.21, 1.1, 0.02, 1.26, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (29, '智械义眼', 'AI 控制的电子义眼，跟你的大脑同步，视域共享后水下任何动静你都看得见。只有播放的广告你怎么也关不掉。', 8, 'general', 1.16, 1.12, 0.05, 1.26, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (30, '暗物质坠饰', '佩戴着一颗"物理外的存在"的坠饰，鱼会下意识地绕道靠近——也就是它们以为自己绕开了你，结果绕到了你的钩上。', 8, 'general', 1.15, 1.18, 0.04, 1.25, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (31, '褪时之颚', '一副交错的不明生物的下颚，颚中有尖柱体形状的舌头诡异地动弹，它总是擅自动起来咬你钓上来的东西，留下一堆圆形的、不会渗血的孔洞伤痕……不知为什么，被咬过的鱼能卖出好价，谁在乎它是不是真的被破坏了。', 9, 'general', 1.2, 1.18, 0.05, 1.31, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (32, '漆黑胎囊', '跳动着的沥青色肉囊，表面凸起有数百颗未睁开的眼球，内部传来胎动般的粘稠挤压声。你不知道它正在孕育什么，只知道把玩起来手感挺有趣，适合钓鱼解压。', 9, 'general', 1.21, 1.23, 0.04, 1.29, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (33, '乾坤鱼篓', '袋内别有洞天，甚至都可以住人了。但进去了还出得来吗？目前为止还没人敢试。', 9, 'general', 1.18, 1.28, 0.03, 1.28, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (34, '太虚引雷钰', '当某些鱼类成长到一定程度，普通的雷已经对它们毫无作用，而此钰可引来附近劫雷为己所用，只需小心别把它们劈渡劫了。', 9, 'general', 1.23, 1.16, 0.06, 1.3, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (35, '龙瞳石', '巨龙留下的眼石，玛瑙般闪烁。佩戴它你能看到水下"龙才能看到的东西"——也就是你不该看到的东西。看了就看了吧，钓鱼要紧。', 9, 'general', 1.21, 1.18, 0.06, 1.31, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (36, '远古德鲁伊种子', '在你包里发芽的远古种子，根系会自己钻出包外伸进水里探鱼。如果你不勤奋地修剪它，再过一周它会把整个钓鱼装备都长成森林。', 9, 'general', 1.19, 1.27, 0.03, 1.29, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (37, '量子断裂腕表', '佩戴它的瞬间，时间在你周围分叉。它向你展示着各种各样的可能性，却让你只能体验到其中一个，所以一切看起来还很正常。', 9, 'general', 1.22, 1.2, 0.05, 1.3, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (38, '维度收纳器', '异维度收纳装置，无视容量限制。你可以一次性把整片海的鱼装进去。但取出来时它会按"被装进去的顺序"排队，所以你本次拿出来的鱼究竟是什么，仍然不可控。', 9, 'general', 1.18, 1.28, 0.04, 1.28, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (39, '千面之皮', '此面可令你化身万物，亦可让你遗忘本质。它会出现在任何事物的可以称得上"脸面"的地方，直到你忘却其原本的样貌。', 10, 'general', 1.27, 1.28, 0.07, 1.31, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (40, '化龙鳞', '当鲤鱼攀上龙瀑、跃过龙门的那一刻，它将忍受生蜕鳞片之苦，以此获得新生，化为真龙。它当时蜕下的鳞片便被称为"化龙鳞"。但凡水族（和龙性恋），皆会被此物吸引。', 10, 'general', 1.27, 1.22, 0.05, 1.31, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (41, '提亚马特的五色金币', '邪龙女王提亚马特宝库中流出的传奇金币，正反面分别铭刻五色龙的爪痕。鱼类送死般吞下你的吊钩，贪婪则逐渐沁入你的内心，这是龙之祝福，也是龙之诅咒。', 10, 'general', 1.24, 1.32, 0.04, 1.31, NULL, NULL);
INSERT INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier", "other_bonus_description", "icon_url") VALUES (42, '量子纠缠浮标', '成成对对的的浮浮标标分分置置两两地地，一一方方咬咬钩钩会会同同步步颤颤动动另另一一方方鱼鱼影影。不仅能双倍效率钓鱼，还会播放环大西洋BGM。', 10, 'general', 1.24, 1.32, 0.07, 1.31, NULL, NULL);
